codeExample:
given().
when().
    get("/store").
then().
    // Flat assertion
    body("store.name", equalTo("Tech Hub")).
    // Deep nested object
    body("store.location.address.city", equalTo("London")).
    // Array element assertion
    body("store.employees[0].role", equalTo("Manager")).
    // Collection assertion (all employee names)
    body("store.employees.name", hasItems("Alice", "Bob")).
    // GPath filtering: count employees older than 30
    body("store.employees.findAll { it.age > 30 }.size()", equalTo(1));
